+#[derive(Clone, serde::Deserialize)]
+pub struct FirecrawlConfig {
+    #[serde(default = "default_base_url")]
+    pub base_url: String,
+    pub api_key: String,
+    #[serde(default)]
+    pub retry: HttpRetryConfig,
+    #[serde(default = "default_timeout_ms")]
