+                    if err.is_retryable() {
+                        return AttemptOutcome::Retryable {
+                            error: err,
+                            retry_after: None,
+                        };
+                    }
+                    return AttemptOutcome::Terminal(err);
+                }
+
+                // Success: parse response
+                let text = match resp.text().await {
+                    Ok(t) => t,
+                    Err(e) => return AttemptOutcome::Terminal(PerplexityError::Http(e)),
+                };
